void kernel_gpu_opencl_wrapper(params_common common, int* endoRow, int* endoCol, int* tEndoRowLoc, int* tEndoColLoc, int* epiRow, int* epiCol, int* tEpiRowLoc, int* tEpiColLoc, avi_t* frames);

void kernel_gpu_opencl_wrapper(params_common common, int* endoRow, int* endoCol, int* tEndoRowLoc, int* tEndoColLoc, int* epiRow, int* epiCol, int* tEpiRowLoc, int* tEpiColLoc, avi_t* frames) {
    int i;
    fp* frame;
    int frame_no;

    // Allocate global buffers needed by the kernel
    fp* d_endoT = (fp*)calloc(common.in_elem * common.endoPoints, sizeof(fp));
    fp* d_epiT = (fp*)calloc(common.in_elem * common.epiPoints, sizeof(fp));
    fp* d_in2_all = (fp*)calloc(common.in2_elem * common.allPoints, sizeof(fp));
    fp* d_conv_all = (fp*)calloc(common.conv_elem * common.allPoints, sizeof(fp));
    fp* d_in2_pad_cumv_all = (fp*)calloc(common.in2_pad_cumv_elem * common.allPoints, sizeof(fp));
    fp* d_in2_pad_cumv_sel_all = (fp*)calloc(common.in2_pad_cumv_sel_elem * common.allPoints, sizeof(fp));
    fp* d_in2_sub_cumh_all = (fp*)calloc(common.in2_sub_cumh_elem * common.allPoints, sizeof(fp));
    fp* d_in2_sub_cumh_sel_all = (fp*)calloc(common.in2_sub_cumh_sel_elem * common.allPoints, sizeof(fp));
    fp* d_in2_sub2_all = (fp*)calloc(common.in2_sub2_elem * common.allPoints, sizeof(fp));
    fp* d_in2_sqr_all = (fp*)calloc(common.in2_sqr_elem * common.allPoints, sizeof(fp));
    fp* d_in2_sqr_sub2_all = (fp*)calloc(common.in2_sqr_sub2_elem * common.allPoints, sizeof(fp));
    fp* d_in_sqr_all = (fp*)calloc(common.in_sqr_elem * common.allPoints, sizeof(fp));
    fp* d_tMask_all = (fp*)calloc(common.tMask_elem * common.allPoints, sizeof(fp));
    fp* d_mask_conv_all = (fp*)calloc(common.mask_conv_elem * common.allPoints, sizeof(fp));
    fp* d_in_mod_temp_all = (fp*)calloc(common.in_elem * common.allPoints, sizeof(fp));
    fp* in_partial_sum_all = (fp*)calloc(common.in_cols * common.allPoints, sizeof(fp));
    fp* in_sqr_partial_sum_all = (fp*)calloc(common.in_sqr_rows * common.allPoints, sizeof(fp));
    fp* par_max_val_all = (fp*)calloc(common.mask_conv_rows * common.allPoints, sizeof(fp));
    int* par_max_coo_all = (int*)calloc(common.mask_conv_rows * common.allPoints, sizeof(int));
    fp* in_final_sum_all = (fp*)calloc(common.allPoints, sizeof(fp));
    fp* in_sqr_final_sum_all = (fp*)calloc(common.allPoints, sizeof(fp));
    fp* denomT_all = (fp*)calloc(common.allPoints, sizeof(fp));
    fp* checksum = (fp*)calloc(CHECK, sizeof(fp));

    printf("frame progress: ");
    fflush(NULL);

    for(frame_no=0; frame_no<common.frames_processed; frame_no++){
        frame = get_frame(frames, frame_no, 0, 0, 1);

        fp* d_frame = frame; 

        #pragma omp parallel for
        for(int bx = 0; bx < common.allPoints; bx++){
            kernel_gpu_opencl(	
                common, 
                d_frame, 
                frame_no, 
                endoRow, 
                endoCol, 
                tEndoRowLoc, 
                tEndoColLoc, 
                epiRow, 
                epiCol, 
                tEpiRowLoc, 
                tEpiColLoc, 
                d_endoT, 
                d_epiT, 
                d_in2_all, 
                d_conv_all, 
                d_in2_pad_cumv_all, 
                d_in2_pad_cumv_sel_all, 
                d_in2_sub_cumh_all, 
                d_in2_sub_cumh_sel_all, 
                d_in2_sub2_all, 
                d_in2_sqr_all, 
                d_in2_sqr_sub2_all, 
                d_in_sqr_all, 
                d_tMask_all, 
                d_mask_conv_all, 
                d_in_mod_temp_all, 
                in_partial_sum_all, 
                in_sqr_partial_sum_all, 
                par_max_val_all, 
                par_max_coo_all, 
                in_final_sum_all, 
                in_sqr_final_sum_all, 
                denomT_all, 
                checksum);
        }

        free(frame);
        printf("%d ", frame_no);
        fflush(NULL);
    }
    printf("\n");
    fflush(NULL);

    // Cleanup buffers
    free(d_endoT); free(d_epiT); free(d_in2_all); free(d_conv_all);
    free(d_in2_pad_cumv_all); free(d_in2_pad_cumv_sel_all); free(d_in2_sub_cumh_all);
    free(d_in2_sub_cumh_sel_all); free(d_in2_sub2_all); free(d_in2_sqr_all);
    free(d_in2_sqr_sub2_all); free(d_in_sqr_all); free(d_tMask_all); free(d_mask_conv_all);
    free(d_in_mod_temp_all); free(in_partial_sum_all); free(in_sqr_partial_sum_all);
    free(par_max_val_all); free(par_max_coo_all); free(in_final_sum_all);
    free(in_sqr_final_sum_all); free(denomT_all); free(checksum);
}

void kernel_gpu_opencl(	
					params_common d_common,					
					fp* d_frame,					
					int d_frame_no,					
					int* d_endoRow,				
					int* d_endoCol,				
					int* d_tEndoRowLoc,			
					int* d_tEndoColLoc,			
					int* d_epiRow,					
					int* d_epiCol,					
					int* d_tEpiRowLoc,				
					int* d_tEpiColLoc,					
					fp* d_endoT,					
					fp* d_epiT,					
					fp* d_in2_all,					
					fp* d_conv_all,				
					fp* d_in2_pad_cumv_all,		
					fp* d_in2_pad_cumv_sel_all,	
					fp* d_in2_sub_cumh_all,		
					fp* d_in2_sub_cumh_sel_all,	
					fp* d_in2_sub2_all,			
					fp* d_in2_sqr_all,				
					fp* d_in2_sqr_sub2_all,		
					fp* d_in_sqr_all,				
					fp* d_tMask_all,				
					fp* d_mask_conv_all,			
					fp* d_in_mod_temp_all,			
					fp* in_partial_sum_all,		
					fp* in_sqr_partial_sum_all,	
					fp* par_max_val_all,			
					int* par_max_coo_all,			
					fp* in_final_sum_all,			
					fp* in_sqr_final_sum_all,		
					fp* denomT_all,					
					fp* checksum)					

{
	int rot_row, rot_col, in2_rowlow, in2_collow, ic, jc, jp1, ja1, ja2, ip1, ia1, ia2, ja, jb, ia, ib;
	fp s;
	int i, j, row, col, ori_row, ori_col, position, pos_ori, location, cent, tMask_row, tMask_col;
	fp sum, temp, temp2, largest_value_current, largest_value, fin_max_val, mean, mean_sqr, variance, deviation;
	int largest_coordinate_current, largest_coordinate, fin_max_coo, largest_row, largest_col, offset_row, offset_col, pointer, ori_pointer, loc_pointer;

	int bx = 0; 
	int tx = 0;
	int ei_new;
	fp* d_common_change_d_frame = d_frame;
	int d_unique_point_no;
	int* d_unique_d_Row;
	int* d_unique_d_Col;
	int* d_unique_d_tRowLoc;
	int* d_unique_d_tColLoc;
	fp* d_in;
	fp* d_unique_d_in2, *d_unique_d_conv, *d_unique_d_in2_pad_cumv, *d_unique_d_in2_pad_cumv_sel;
	fp* d_unique_d_in2_sub_cumh, *d_unique_d_in2_sub_cumh_sel, *d_unique_d_in2_sub2, *d_unique_d_in2_sqr;
	fp* d_unique_d_in2_sqr_sub2, *d_unique_d_in_sqr, *d_unique_d_tMask, *d_unique_d_mask_conv;
	fp* d_in_mod_temp, *in_partial_sum, *in_sqr_partial_sum, *par_max_val;
	int* par_max_coo;
	fp* in_final_sum, *in_sqr_final_sum, *denomT;

	if(bx < d_common.endoPoints){
		d_unique_point_no = bx;
		d_unique_d_Row = d_endoRow;
		d_unique_d_Col = d_endoCol;
		d_unique_d_tRowLoc = d_tEndoRowLoc;
		d_unique_d_tColLoc = d_tEndoColLoc;
		d_in = &d_endoT[d_unique_point_no * d_common.in_elem];
		d_unique_d_in2 = &d_in2_all[bx*d_common.in2_elem];
		d_unique_d_conv = &d_conv_all[bx*d_common.conv_elem];
		d_unique_d_in2_pad_cumv = &d_in2_pad_cumv_all[bx*d_common.in2_pad_cumv_elem];
		d_unique_d_in2_pad_cumv_sel = &d_in2_pad_cumv_sel_all[bx*d_common.in2_pad_cumv_sel_elem];
		d_unique_d_in2_sub_cumh = &d_in2_sub_cumh_all[bx*d_common.in2_sub_cumh_elem];
		d_unique_d_in2_sub_cumh_sel = &d_in2_sub_cumh_sel_all[bx*d_common.in2_sub_cumh_sel_elem];
		d_unique_d_in2_sub2 = &d_in2_sub2_all[bx*d_common.in2_sub2_elem];
		d_unique_d_in2_sqr = &d_in2_sqr_all[bx*d_common.in2_sqr_elem];
		d_unique_d_in2_sqr_sub2 = &d_in2_sqr_sub2_all[bx*d_common.in2_sqr_sub2_elem];
		d_unique_d_in_sqr = &d_in_sqr_all[bx*d_common.in_sqr_elem];
		d_unique_d_tMask = &d_tMask_all[bx*d_common.tMask_elem];
		d_unique_d_mask_conv = &d_mask_conv_all[bx*d_common.mask_conv_elem];
		d_in_mod_temp = &d_in_mod_temp_all[bx*d_common.in_elem];
		in_partial_sum = &in_partial_sum_all[bx*d_common.in_cols];
		in_sqr_partial_sum = &in_sqr_partial_sum_all[bx*d_common.in_sqr_rows];
		par_max_val = &par_max_val_all[bx*d_common.mask_conv_rows];
		par_max_coo = &par_max_coo_all[bx*d_common.mask_conv_rows];
		in_final_sum = &in_final_sum_all[bx];
		in_sqr_final_sum = &in_sqr_final_sum_all[bx];
		denomT = &denomT_all[bx];
	} else {
		d_unique_point_no = bx-d_common.endoPoints;
		d_unique_d_Row = d_epiRow;
		d_unique_d_Col = d_epiCol;
		d_unique_d_tRowLoc = d_tEpiRowLoc;
		d_unique_d_tColLoc = d_tEpiColLoc;
		d_in = &d_epiT[d_unique_point_no * d_common.in_elem];
		d_unique_d_in2 = &d_in2_all[bx*d_common.in2_elem];
		d_unique_d_conv = &d_conv_all[bx*d_common.conv_elem];
		d_unique_d_in2_pad_cumv = &d_in2_pad_cumv_all[bx*d_common.in2_pad_cumv_elem];
		d_unique_d_in2_pad_cumv_sel = &d_in2_pad_cumv_sel_all[bx*d_common.in2_pad_cumv_sel_elem];
		d_unique_d_in2_sub_cumh = &d_in2_sub_cumh_all[bx*d_common.in2_sub_cumh_elem];
		d_unique_d_in2_sub_cumh_sel = &d_in2_sub_cumh_sel_all[bx*d_common.in2_sub_cumh_sel_elem];
		d_unique_d_in2_sub2 = &d_in2_sub2_all[bx*d_common.in2_sub2_elem];
		d_unique_d_in2_sqr = &d_in2_sqr_all[bx*d_common.in2_sqr_elem];
		d_unique_d_in2_sqr_sub2 = &d_in2_sqr_sub2_all[bx*d_common.in2_sqr_sub2_elem];
		d_unique_d_in_sqr = &d_in_sqr_all[bx*d_common.in_sqr_elem];
		d_unique_d_tMask = &d_tMask_all[bx*d_common.tMask_elem];
		d_unique_d_mask_conv = &d_mask_conv_all[bx*d_common.mask_conv_elem];
		d_in_mod_temp = &d_in_mod_temp_all[bx*d_common.in_elem];
		in_partial_sum = &in_partial_sum_all[bx*d_common.in_cols];
		in_sqr_partial_sum = &in_sqr_partial_sum_all[bx*d_common.in_sqr_rows];
		par_max_val = &par_max_val_all[bx*d_common.mask_conv_rows];
		par_max_coo = &par_max_coo_all[bx*d_common.mask_conv_rows];
		in_final_sum = &in_final_sum_all[bx];
		in_sqr_final_sum = &in_sqr_final_sum_all[bx];
		denomT = &denomT_all[bx];
	}

#ifdef TEST_CHECKSUM
	if(bx==0 && tx==0){
		for(i=0; i<CHECK; i++){ checksum[i] = 0; }
	}
#endif

	if(d_frame_no == 0){
#ifdef INIT
		if(tx==0){
			for(i=0; i<d_common.no_frames; i++){
				d_unique_d_tRowLoc[d_unique_point_no*d_common.no_frames+i] = 0;
				d_unique_d_tColLoc[d_unique_point_no*d_common.no_frames+i] = 0;
			}
			for(i=0; i<d_common.in_elem; i++){ d_in[i] = 0; }
		}
#endif
		ei_new = tx;
		if(ei_new == 0){
			pointer = d_unique_point_no*d_common.no_frames+d_frame_no;
			d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no];
			d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no];
		}
		ei_new = tx;
		while(ei_new < d_common.in_elem){
			row = (ei_new+1) % d_common.in_rows - 1;
			col = (ei_new+1) / d_common.in_rows + 1 - 1;
			if((ei_new+1) % d_common.in_rows == 0){ row = d_common.in_rows - 1; col = col-1; }
			ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
			ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
			ori_pointer = ori_col*d_common.frame_rows+ori_row;
			d_in[col*d_common.in_rows+row] = d_common_change_d_frame[ori_pointer];
			ei_new = ei_new + NUMBER_THREADS;
		}
#ifdef TEST_CHECKSUM
		if(bx==0 && tx==0){
			for(i=0; i<d_common.in_elem; i++){ checksum[0] += d_in[i]; }
		}
#endif
	}

	if(d_frame_no != 0){
#ifdef INIT
		if(tx==0){
			for(i=0; i<d_common.in2_elem; i++) d_unique_d_in2[i] = 0;
			for(i=0; i<d_common.conv_elem; i++) d_unique_d_conv[i] = 0;
			for(i=0; i<d_common.in2_pad_cumv_elem; i++) d_unique_d_in2_pad_cumv[i] = 0;
			for(i=0; i<d_common.in2_pad_cumv_sel_elem; i++) d_unique_d_in2_pad_cumv_sel[i] = 0;
			for(i=0; i<d_common.in2_sub_cumh_elem; i++) d_unique_d_in2_sub_cumh[i] = 0;
			for(i=0; i<d_common.in2_sub_cumh_sel_elem; i++) d_unique_d_in2_sub_cumh_sel[i] = 0;
			for(i=0; i<d_common.in2_sub2_elem; i++) d_unique_d_in2_sub2[i] = 0;
			for(i=0; i<d_common.in2_sqr_elem; i++) d_unique_d_in2_sqr[i] = 0;
			for(i=0; i<d_common.in2_sqr_sub2_elem; i++) d_unique_d_in2_sqr_sub2[i] = 0;
			for(i=0; i<d_common.in_sqr_elem; i++) d_unique_d_in_sqr[i] = 0;
			for(i=0; i<d_common.tMask_elem; i++) d_unique_d_tMask[i] = 0;
			for(i=0; i<d_common.mask_conv_elem; i++) d_unique_d_mask_conv[i] = 0;
			for(i=0; i<d_common.in_elem; i++) d_in_mod_temp[i] = 0;
			for(i=0; i<d_common.in_cols; i++) in_partial_sum[i] = 0;
			for(i=0; i<d_common.in_sqr_rows; i++) in_sqr_partial_sum[i] = 0;
