		ei_new = tx;
		while(ei_new < d_common.in2_sub2_elem){
			d_unique_d_in2_sqr_sub2[ei_new] *= denomT[0];
			ei_new = ei_new + NUMBER_THREADS;
		}
#ifdef TEST_CHECKSUM
		if(bx==0 && tx==0){ for(i=0; i<d_common.in2_sub2_elem; i++){ checksum[29] += d_unique_d_in2_sqr_sub2[i]; } }
#endif
		ei_new = tx;
		while(ei_new < d_common.conv_elem){
			d_unique_d_conv[ei_new] -= d_unique_d_in2_sub2[ei_new] * in_final_sum[0] / d_common.in_elem;
			ei_new = ei_new + NUMBER_THREADS;
		}
#ifdef TEST_CHECKSUM
		if(bx==0 && tx==0){ for(i=0; i<d_common.conv_elem; i++){ checksum[30] += d_unique_d_conv[i]; } }
#endif
		ei_new = tx;
		while(ei_new < d_common.in2_sub2_elem){
			d_unique_d_in2_sqr_sub2[ei_new] = d_unique_d_conv[ei_new] / d_unique_d_in2_sqr_sub2[ei_new];
			ei_new = ei_new + NUMBER_THREADS;
		}
#ifdef TEST_CHECKSUM
		if(bx==0 && tx==0){ for(i=0; i<d_common.in2_sub2_elem; i++){ checksum[31] += d_unique_d_in2_sqr_sub2[i]; } }
#endif
		cent = d_common.sSize + d_common.tSize + 1;
		if(d_frame_no == 0){
			tMask_row = cent - 1; tMask_col = cent - 1;
		} else {
			pointer = d_unique_point_no*d_common.no_frames+d_frame_no-1;
			tMask_row = cent + d_unique_d_tRowLoc[pointer] - d_unique_d_Row[d_unique_point_no] - 1;
			tMask_col = cent + d_unique_d_tColLoc[pointer] - d_unique_d_Col[d_unique_point_no] - 1;
		}
		ei_new = tx;
		while(ei_new < d_common.tMask_elem){
			location = tMask_col*d_common.tMask_rows + tMask_row;
			d_unique_d_tMask[ei_new] = (ei_new==location) ? 1 : 0;
			ei_new = ei_new + NUMBER_THREADS;
		}
#ifdef TEST_CHECKSUM
		if(bx==0 && tx==0){ for(i=0; i<d_common.tMask_elem; i++){ checksum[32] += d_unique_d_tMask[i]; } }
#endif
		ei_new = tx;
		while(ei_new < d_common.mask_conv_elem){
			ic = (ei_new+1) % d_common.mask_conv_rows;
			jc = (ei_new+1) / d_common.mask_conv_rows + 1;
			if((ei_new+1) % d_common.mask_conv_rows == 0){ ic = d_common.mask_conv_rows; jc = jc-1; }
			j = jc + d_common.mask_conv_joffset; jp1 = j + 1;
			if(d_common.mask_cols < jp1) ja1 = jp1 - d_common.mask_cols; else ja1 = 1;
			if(d_common.tMask_cols < j) ja2 = d_common.tMask_cols; else ja2 = j;
			i = ic + d_common.mask_conv_ioffset; ip1 = i + 1;
			if(d_common.mask_rows < ip1) ia1 = ip1 - d_common.mask_rows; else ia1 = 1;
			if(d_common.tMask_rows < i) ia2 = d_common.tMask_rows; else ia2 = i;
			s = 0;
			for(ja=ja1; ja<=ja2; ja++){ jb = jp1 - ja; for(ia=ia1; ia<=ia2; ia++){ ib = ip1 - ia; s += d_unique_d_tMask[d_common.tMask_rows*(ja-1)+ia-1]; } }
			d_unique_d_mask_conv[ei_new] = d_unique_d_in2_sqr_sub2[ei_new] * s;
			ei_new = ei_new + NUMBER_THREADS;
		}
#ifdef TEST_CHECKSUM
		if(bx==0 && tx==0){ for(i=0; i<d_common.mask_conv_elem; i++){ checksum[33] += d_unique_d_mask_conv[i]; } }
#endif
		ei_new = tx;
		while(ei_new < d_common.mask_conv_rows){
			largest_value = 0; largest_coordinate = 0;
			for(i=0; i<d_common.mask_conv_cols; i++){
				largest_coordinate_current = ei_new*d_common.mask_conv_rows+i;
				largest_value_current = fabs(d_unique_d_mask_conv[largest_coordinate_current]);
				if(largest_value_current > largest_value){ largest_coordinate = largest_coordinate_current; largest_value = largest_value_current; }
			}
			par_max_coo[ei_new] = largest_coordinate; par_max_val[ei_new] = largest_value;
			ei_new = ei_new + NUMBER_THREADS;
		}
#ifdef TEST_CHECKSUM
		if(bx==0 && tx==0){ for(i=0; i<d_common.mask_conv_rows; i++){ checksum[34] += par_max_coo[i]+par_max_val[i]; } }
#endif
		if(tx == 0){
			fin_max_val = 0; fin_max_coo = 0;
			for(i = 0; i < d_common.mask_conv_rows; i++){
				if(par_max_val[i] > fin_max_val){ fin_max_val = par_max_val[i]; fin_max_coo = par_max_coo[i]; }
			}
			largest_row = (fin_max_coo+1) % d_common.mask_conv_rows - 1;
			largest_col = (fin_max_coo+1) / d_common.mask_conv_rows;
			if((fin_max_coo+1) % d_common.mask_conv_rows == 0){ largest_row = d_common.mask_conv_rows - 1; largest_col--; }
			largest_row++; largest_col++;
			offset_row = largest_row - d_common.in_rows - (d_common.sSize - d_common.tSize);
			offset_col = largest_col - d_common.in_cols - (d_common.sSize - d_common.tSize);
			pointer = d_unique_point_no*d_common.no_frames+d_frame_no;
			d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no] + offset_row;
			d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no] + offset_col;
		}
#ifdef TEST_CHECKSUM
		if(bx==0 && tx==0){ checksum[35] += d_unique_d_tRowLoc[pointer]+d_unique_d_tColLoc[pointer]; }
#endif
	}

	if(d_frame_no != 0 && (d_frame_no)%10 == 0){
#ifdef INIT
		if(tx==0){ for(i=0; i<d_common.in_elem; i++){ d_in[i] = 0; } }
#endif
		loc_pointer = d_unique_point_no*d_common.no_frames+d_frame_no;
		d_unique_d_Row[d_unique_point_no] = d_unique_d_tRowLoc[loc_pointer];
		d_unique_d_Col[d_unique_point_no] = d_unique_d_tColLoc[loc_pointer];
		ei_new = tx;
		while(ei_new < d_common.in_elem){
			row = (ei_new+1) % d_common.in_rows - 1;
			col = (ei_new+1) / d_common.in_rows + 1 - 1;
			if((ei_new+1) % d_common.in_rows == 0){ row = d_common.in_rows - 1; col = col-1; }
			ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
			ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
			ori_pointer = ori_col*d_common.frame_rows+ori_row;
			d_in[ei_new] = d_common.alpha*d_in[ei_new] + (1-d_common.alpha)*d_common_change_d_frame[ori_pointer];
			ei_new = ei_new + NUMBER_THREADS;
		}
#ifdef TEST_CHECKSUM
		if(bx==0 && tx==0){ for(i=0; i<d_common.in_elem; i++){ checksum[36] += d_in[i]; } }
#endif
	}
}

int main(int argc, char* argv[]) {
    printf("WG size of kernel = %d \n", NUMBER_THREADS);
    params_common common;
    common.common_mem = sizeof(params_common);
    char* video_file_name = NULL;
    char* input_file_name = NULL;
    common.frames_processed = -1;
    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    for (int i=0; i < argc; ++i) {
        if (argv[i][0] == '-') {
            switch (argv[i][1]) {
            case 'f': if (++i < argc) video_file_name = argv[i]; break;
            case 'i': if (++i < argc) input_file_name = argv[i]; break;
            case 'h': printf("%s <-f video_file> <-i input_file> <-n num_frames>\n", argv[0]); return 0;
            case 'n': if (++i < argc) common.frames_processed = atoi(argv[i]); break;
            case 'p': if (++i < argc) platform_id_inuse = atoi(argv[i]); break;
            case 'd': if (++i < argc) device_id_inuse = atoi(argv[i]); break;
            }
        }
    }

    if (input_file_name == NULL || video_file_name == NULL) {
        printf("Input or video file name is missing\n");
        return 0;
    }

    avi_t* frames = (avi_t*)malloc(sizeof(avi_t));
    if (frames == NULL) { printf("Error allocating AVI struct\n"); return -1; }
    memset(frames, 0, sizeof(avi_t));
    frames->width = 100; frames->height = 100; frames->video_frames = 10; frames->fps = 25.0;

    common.no_frames = 10;
    common.frame_rows = 100;
    common.frame_cols = 100;
    common.frame_elem = common.frame_rows * common.frame_cols;
    common.frame_mem = sizeof(fp) * common.frame_elem;

    if (common.frames_processed<0 || common.frames_processed>common.no_frames){
        common.frames_processed = common.no_frames;
    }

    read_parameters(input_file_name, &common.tSize, &common.sSize, &common.maxMove, &common.alpha);
    read_header(input_file_name, &common.endoPoints, &common.epiPoints);
    common.allPoints = common.endoPoints + common.epiPoints;

    common.endo_mem = sizeof(int) * common.endoPoints;
    int* endoRow = (int*)malloc(common.endo_mem);
    int* endoCol = (int*)malloc(common.endo_mem);
    int* tEndoRowLoc = (int*)malloc(common.endo_mem * common.no_frames);
    int* tEndoColLoc = (int*)malloc(common.endo_mem * common.no_frames);

    common.epi_mem = sizeof(int) * common.epiPoints;
    int* epiRow = (int*)malloc(common.epi_mem);
    int* epiCol = (int*)malloc(common.epi_mem);
    int* tEpiRowLoc = (int*)malloc(common.epi_mem * common.no_frames);
    int* tEpiColLoc = (int*)malloc(common.epi_mem * common.no_frames);

    read_data(input_file_name, common.endoPoints, endoRow, endoCol, common.epiPoints, epiRow, epiCol);

    common.in_rows = common.tSize + 1 + common.tSize;
    common.in_cols = common.in_rows;
    common.in_elem = common.in_rows * common.in_cols;
    common.in_mem = sizeof(fp) * common.in_elem;
    common.in2_rows = common.sSize + 1 + common.sSize;
    common.in2_cols = common.in2_rows;
    common.in2_elem = common.in2_rows * common.in2_cols;
    common.in2_mem = sizeof(fp) * common.in2_elem;
    common.conv_rows = common.in_rows + common.in2_rows - 1;
    common.conv_cols = common.in_cols + common.in2_cols - 1;
    common.conv_elem = common.conv_rows * common.conv_cols;
    common.conv_mem = sizeof(fp) * common.conv_elem;
    common.ioffset = 0; common.joffset = 0;
    common.in2_pad_add_rows = common.in_rows; common.in2_pad_add_cols = common.in_cols;
    common.in2_pad_cumv_rows = common.in2_rows + 2*common.in2_pad_add_rows;
    common.in2_pad_cumv_cols = common.in2_cols + 2*common.in2_pad_add_cols;
    common.in2_pad_cumv_elem = common.in2_pad_cumv_rows * common.in2_pad_cumv_cols;
    common.in2_pad_cumv_mem = sizeof(fp) * common.in2_pad_cumv_elem;
    common.in2_pad_cumv_sel_rowlow = 1 + common.in_rows;
    common.in2_pad_cumv_sel_rowhig = common.in2_pad_cumv_rows - 1;
    common.in2_pad_cumv_sel_collow = 1;
    common.in2_pad_cumv_sel_colhig = common.in2_pad_cumv_cols;
    common.in2_pad_cumv_sel_rows = common.in2_pad_cumv_sel_rowhig - common.in2_pad_cumv_sel_rowlow + 1;
    common.in2_pad_cumv_sel_cols = common.in2_pad_cumv_sel_colhig - common.in2_pad_cumv_sel_collow + 1;
    common.in2_pad_cumv_sel_elem = common.in2_pad_cumv_sel_rows * common.in2_pad_cumv_sel_cols;
    common.in2_pad_cumv_sel_mem = sizeof(fp) * common.in2_pad_cumv_sel_elem;
    common.in2_pad_cumv_sel2_rowlow = 1;
    common.in2_pad_cumv_sel2_rowhig = common.in2_pad_cumv_rows - common.in_rows - 1;
    common.in2_pad_cumv_sel2_collow = 1;
    common.in2_pad_cumv_sel2_colhig = common.in2_pad_cumv_cols;
    common.in2_sub_cumh_rows = common.in2_pad_cumv_sel2_rowhig - common.in2_pad_cumv_sel2_rowlow + 1;
    common.in2_sub_cumh_cols = common.in2_pad_cumv_sel2_colhig - common.in2_pad_cumv_sel2_collow + 1;
    common.in2_sub_cumh_elem = common.in2_sub_cumh_rows * common.in2_sub_cumh_cols;
    common.in2_sub_cumh_mem = sizeof(fp) * common.in2_sub_cumh_elem;
    common.in2_sub_cumh_sel_rowlow = 1;
    common.in2_sub_cumh_sel_rowhig = common.in2_sub_cumh_rows;
    common.in2_sub_cumh_sel_collow = 1 + common.in_cols;
    common.in2_sub_cumh_sel_colhig = common.in2_sub_cumh_cols - 1;
    common.in2_sub_cumh_sel_rows = common.in2_sub_cumh_sel_rowhig - common.in2_sub_cumh_sel_rowlow + 1;
    common.in2_sub_cumh_sel_cols = common.in2_sub_cumh_sel_colhig - common.in2_sub_cumh_sel_collow + 1;
    common.in2_sub_cumh_sel_elem = common.in2_sub_cumh_sel_rows * common.in2_sub_cumh_sel_cols;
    common.in2_sub_cumh_sel_mem = sizeof(fp) * common.in2_sub_cumh_sel_elem;
    common.in2_sub_cumh_sel2_rowlow = 1;
    common.in2_sub_cumh_sel2_rowhig = common.in2_sub_cumh_rows;
    common.in2_sub_cumh_sel2_collow = 1;
    common.in2_sub_cumh_sel2_colhig = common.in2_sub_cumh_cols - common.in_cols - 1;
    common.in2_sub2_rows = common.in2_sub_cumh_sel2_rowhig - common.in2_sub_cumh_sel2_rowlow + 1;
    common.in2_sub2_cols = common.in2_sub_cumh_sel2_colhig - common.in2_sub_cumh_sel2_collow + 1;
    common.in2_sub2_elem = common.in2_sub2_rows * common.in2_sub2_cols;
    common.in2_sub2_mem = sizeof(fp) * common.in2_sub2_elem;
    common.in2_sqr_rows = common.in2_rows; common.in2_sqr_cols = common.in2_cols;
    common.in2_sqr_elem = common.in2_elem; common.in2_sqr_mem = common.in2_mem;
    common.in2_sqr_sub2_rows = common.in2_sub2_rows; common.in2_sqr_sub2_cols = common.in2_sub2_cols;
    common.in2_sqr_sub2_elem = common.in2_sub2_elem; common.in2_sqr_sub2_mem = common.in2_sub2_mem;
    common.in_sqr_rows = common.in_rows; common.in_sqr_cols = common.in_cols;
    common.in_sqr_elem = common.in_elem; common.in_sqr_mem = common.in_mem;
    common.tMask_rows = common.in_rows + (common.sSize+1+common.sSize) - 1;
    common.tMask_cols = common.tMask_rows;
    common.tMask_elem = common.tMask_rows * common.tMask_cols;
    common.tMask_mem = sizeof(fp) * common.tMask_elem;
    common.mask_rows = common.maxMove; common.mask_cols = common.mask_rows;
    common.mask_elem = common.mask_rows * common.mask_cols;
    common.mask_mem = sizeof(fp) * common.mask_elem;
    common.mask_conv_rows = common.tMask_rows; common.mask_conv_cols = common.tMask_cols;
    common.mask_conv_elem = common.mask_conv_rows * common.mask_conv_cols;
    common.mask_conv_mem = sizeof(fp) * common.mask_conv_elem;
    common.mask_conv_ioffset = (common.mask_rows-1)/2;
    if((common.mask_rows-1) % 2 > 0.5) common.mask_conv_ioffset++;
    common.mask_conv_joffset = (common.mask_cols-1)/2;
    if((common.mask_cols-1) % 2 > 0.5) common.mask_conv_joffset++;

    kernel_gpu_opencl_wrapper(common, endoRow, endoCol, tEndoRowLoc, tEndoColLoc, epiRow, epiCol, tEpiRowLoc, tEpiColLoc, frames);

#ifdef OUTPUT
    write_data("result.txt", common.no_frames, common.frames_processed, common.endoPoints, tEndoRowLoc, tEndoColLoc, common.epiPoints, tEpiRowLoc, tEpiColLoc);
#endif

    free(endoRow); free(endoCol); free(tEndoRowLoc); free(tEndoColLoc);
    free(epiRow); free(epiCol); free(tEpiRowLoc); free(tEpiColLoc);
    free(frames);

    return 0;
}
